mapper.insert:
INSERT INTO rag_chat_sessions (
    session_id, user_id, title, preview, message_count, manual_title, deleted, created_at, updated_at
) VALUES (
    #{sessionId}, #{userId}, #{title}, #{preview}, #{messageCount}, #{manualTitle}, #{deleted}, #{createdAt}, #{updatedAt}
)

mapper.update:
UPDATE rag_chat_sessions
SET
    title = #{title},
    preview = #{preview},
    message_count = #{messageCount},
    deleted = #{deleted},
    updated_at = #{updatedAt}
WHERE user_id = #{userId}
  AND session_id = #{sessionId}

UPDATE rag_chat_sessions
SET
    deleted = #{deleted},
    updated_at = CURRENT_TIMESTAMP
WHERE user_id = #{userId}
  AND session_id = #{sessionId}

mapper.delete:
DELETE FROM rag_chat_sessions
WHERE user_id = #{userId}
  AND session_id = #{sessionId}
